## Plot: Feature Count by Mode

::: {#cell-plot-modes .cell execution_count=9}
``` {.python .cell-code}
import matplotlib.pyplot as plt

mode_df = pd.DataFrame.from_dict(mode_results, orient="index")
if "features" in mode_df.columns:
    mode_df = mode_df.dropna(subset=["features"])
    fig, ax = plt.subplots(figsize=(8, 4))
    mode_df["features"].plot(kind="bar", ax=ax, color="steelblue")
    ax.set_title("Generated Features by Pipeline Mode")
    ax.set_ylabel("Number of Features")
    ax.set_xlabel("Mode")
    ax.tick_params(axis="x", rotation=45)
    plt.tight_layout()
    plt.show()
